mapper.select:
select count(*)
from project_version
where project_id = #{projectId}
  and version_id = #{versionId}
  and status_code != 'k003'

select count(*)
from milestone m
join project_version v
  on m.version_id = v.version_id
 and m.project_id = v.project_id
where m.project_id = #{projectId}
  and m.version_id = #{versionId}
  and m.milestone_id = #{milestoneId}
  and v.status_code != 'k003'

select count(*)
from project_member pm
join team_member tm
  on pm.team_member_id = tm.team_member_id
where pm.project_id = #{projectId}
  and tm.user_id = #{assigneeId}

select count(*)
from issue
where project_id = #{projectId}
  and issue_id = #{parentIssueId}
